defmodule WordCount do
  @moduledoc """
  Counts words in text or in a file.

  Words are counted as whitespace-separated tokens, matching the behavior of
  `wc -w` for normal text.
  """

  @doc """
  Counts whitespace-separated words in a string.

  ## Examples

      iex> WordCount.count_words("one two three")
      3

      iex> WordCount.count_words("")
      0
  """
  @spec count_words(String.t()) :: non_neg_integer()
  def count_words(text) when is_binary(text) do
    text
    |> String.split(~r/\s+/u, trim: true)
    |> length()
  end

  @doc """
  Alias for `count_words/1`.
  """
  @spec count(String.t()) :: non_neg_integer()
  def count(text), do: count_words(text)

  @doc """
  Counts words in the file at `path`.
  """
  @spec count_words_in_file(Path.t()) :: {:ok, non_neg_integer()} | {:error, term()}
  def count_words_in_file(path) when is_binary(path) do
    case File.read(path) do
      {:ok, contents} -> {:ok, count_words(contents)}
      error -> error
    end
  end

  @doc """
  Counts words in one or more files, returning `{:ok, result}`.

  For a single file, result is an integer. For multiple files, result is a map
  of path to count.
  """
  @spec count_words_in_files([Path.t()]) :: {:ok, non_neg_integer() | map()} | {:error, term()}
  def count_words_in_files(paths) when is_list(paths) do
    Enum.reduce_while(paths, %{}, fn path, counts ->
      case count_words_in_file(path) do
        {:ok, count} -> {:cont, Map.put(counts, path, count)}
        error -> {:halt, error}
      end
    end)
    |> case do
      {:ok, counts} -> {:ok, format_counts(counts)}
      error -> error
    end
  end

  defp format_counts(%{path: count}), do: count
  defp format_counts(counts), do: counts
end
